  await pool.query("DELETE FROM assistance_centers");
  await pool.query("DELETE FROM jobs");
  await pool.query("DELETE FROM schemes");
  await pool.query("ALTER SEQUENCE schemes_id_seq RESTART WITH 1");
  await pool.query("ALTER SEQUENCE jobs_id_seq RESTART WITH 1");
  await pool.query("ALTER SEQUENCE assistance_centers_id_seq RESTART WITH 1");
